// LoadUserRoles performs the eager-load for the "roles" edge. Body mirrors
// the pre-PR6 *UserQuery.loadRoles method, hoisted to root
// so it can reference cross-package types directly.
func LoadUserRoles(ctx context.Context, query *role.RoleQuery, nodes []*user.User) error {
	edgeIDs := make([]driver.Value, len(nodes))
	byID := make(map[int]*user.User)
	nids := make(map[int]map[*user.User]struct{})
	for i, node := range nodes {
		edgeIDs[i] = node.ID
		byID[node.ID] = node
		node.Edges.Roles = []*role.Role{}
	}
	query.Where(func(s *sql.Selector) {
		joinT := sql.Table(user.RolesTable)
		s.Join(joinT).On(s.C(role.FieldID), joinT.C(user.RolesPrimaryKey[1]))
		s.Where(sql.InValues(joinT.C(user.RolesPrimaryKey[0]), edgeIDs...))
		columns := s.SelectedColumns()
		s.Select(joinT.C(user.RolesPrimaryKey[0]))
		s.AppendSelect(columns...)
		s.SetDistinct(false)
	})
	if err := query.PrepareQuery(ctx); err != nil {
		return err
	}
	qr := QuerierFunc(func(ctx context.Context, q Query) (Value, error) {
		return query.Fetch(ctx, func(_ context.Context, spec *sqlgraph.QuerySpec) {
			assign := spec.Assign
			values := spec.ScanValues
			spec.ScanValues = func(columns []string) ([]any, error) {
				values, err := values(columns[1:])
				if err != nil {
					return nil, err
				}
				return append([]any{new(sql.NullInt64)}, values...), nil
			}
			spec.Assign = func(columns []string, values []any) error {
				outValue := int(values[0].(*sql.NullInt64).Int64)
				inValue := int(values[1].(*sql.NullInt64).Int64)
				if nids[inValue] == nil {
					nids[inValue] = map[*user.User]struct{}{byID[outValue]: {}}
					return assign(columns[1:], values[1:])
				}
				nids[inValue][byID[outValue]] = struct{}{}
				return nil
			}
		})
	})
	neighbors, err := withInterceptors[[]*role.Role](ctx, query, qr, query.QueryState.Inters)
	if err != nil {
		return err
	}
	for _, n := range neighbors {
		parents, ok := nids[n.ID]
		if !ok {
			return fmt.Errorf(`unexpected "roles" node returned %v`, n.ID)
		}
		for kn := range parents {
			kn.Edges.Roles = append(kn.Edges.Roles, n)
		}
	}
	for _, loader := range query.EagerLoaders() {
		if err := loader(ctx, neighbors); err != nil {
			return err
		}
	}
	return nil
}

